1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string };
14	type Step = { op: "quote"; items: Item[] };
15	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
16	
17	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_BASE_PREMIUM = 60;
22	
23	const sumBasePremiums = (items: Item[]): number =>
24	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
25	
26	const allSameType = (items: Item[]): boolean =>
27	  items.every((item) => item.type === items[0].type);
28	
29	const componentGroupSubtotalOf = (group: Item[]): number => {
30	  if (group.length === BLOCK_SIZE) {
31	    return BLOCK_BASE_PREMIUM;
32	  }
33	  return sumBasePremiums(group);
34	};
35	
36	const groupByType = (items: Item[]): Map<string, Item[]> => {
37	  const groups = new Map<string, Item[]>();
38	  for (const item of items) {
39	    const existing = groups.get(item.type) ?? [];
40	    existing.push(item);
41	    groups.set(item.type, existing);
42	  }
43	  return groups;
44	};
45	
46	const componentSubtotalOf = (components: Item[]): number => {
47	  const groups = groupByType(components);
48	  let total = 0;
49	  for (const group of groups.values()) {
50	    total += componentGroupSubtotalOf(group);
51	  }
52	  return total;
53	};
54	
55	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
56	
57	const policyBaseOf = (items: Item[]): number => {
58	  const components = items.filter(isComponent);
59	  const mainItems = items.filter((item) => !isComponent(item));
60	  return sumBasePremiums(mainItems) + componentSubtotalOf(components);
61	};
62	
63	const firstInsuranceSurchargeOf = (policyBase: number): number =>
64	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
65	
66	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
67	
68	const quotePremium = (items: Item[]): number => {
69	  const policyBase = policyBaseOf(items);
70	  const rawPremium = policyBase + firstInsuranceSurchargeOf(policyBase) + PROCESSING_FEE;
71	  return roundUpInMHPCOFavor(rawPremium);
72	};
73	
74	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
75	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
76	  return { results };
77	};
